    return challenges[next];
  }

  function loadChallenge() {
    var ch = pickChallenge();
    document.getElementById('el-prompt').innerHTML = ch.prompt;
    var wrap = document.getElementById('editor-endless');
    wrap.innerHTML = '';
    PyLearn.createEditor({
      containerId: 'editor-endless',
      persist: false,
      initialCode: '# Write your solution\n',
      label: 'GCSE Endless',
      validate: async function(output, error, code) {
        var c = challenges[currentIdx];
        var inputs = c.inputs.slice();
        var r = await PyLearn.runPython(code, { inputs: inputs });
        if (r.error) return { pass: false, message: '\u274c Problem: ' + r.error };
        if (!r.output.trim()) return { pass: false, message: '\u26a0\ufe0f Nothing was printed!' };
        // Check expected number if any
        if (c.expectedNumber !== null) {
          if (r.output.indexOf(c.expectedNumber) === -1) {
            return { pass: false, message: '\u274c Expected the number ' + c.expectedNumber + ' in the output. Got: "' + r.output.trim() + '"' };
          }
        }
        // Check expected words
        var wordRe = new RegExp(c.expectedWords, 'i');
        if (!wordRe.test(r.output)) {
          return { pass: false, message: '\u274c Add a clear label to your output (something like "total" or "highest").' };
        }
        // Check loop type
        if (c.requireWhile) {
          if (!/while/.test(code)) return { pass: false, message: '\u26a0\ufe0f This question needs a while loop, not a for loop.' };
        } else {
          if (!/for|while/.test(code)) return { pass: false, message: '\u26a0\ufe0f Please use a loop.' };
